import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useSlides } from "../contexts/SlideContext";
import { Slide, ImageSlide, SLIDE_TYPES, ImageSlideData } from "../types";

interface SlideTypeCard {
    type: typeof SLIDE_TYPES.IMAGE;
    title: string;
    description: string;
    icon: React.ReactNode;
}

interface EditModalProps {
    isOpen: boolean;
    onClose: () => void;
    slide: ImageSlide | null;
    onSave: (slide: ImageSlide) => void;
}

const SLIDE_TYPE_CARDS: SlideTypeCard[] = [
    {
        type: SLIDE_TYPES.IMAGE,
        title: "Image Slider",
        description: "Create a slideshow with images and optional captions",
        icon: (
            <svg
                className="w-8 h-8"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
            >
                <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth="2"
                    d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"
                />
            </svg>
        ),
    },
    // Add more slide types here as needed
];

const EditModal: React.FC<EditModalProps> = ({ isOpen, onClose, slide, onSave }) => {
    const [editedSlide, setEditedSlide] = useState<ImageSlide | null>(slide);

    const handleSave = () => {
        if (editedSlide) {
            onSave(editedSlide);
            onClose();
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
            <motion.div
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.95 }}
                className="bg-white rounded-xl shadow-xl w-full max-w-2xl p-6"
            >
                <div className="flex items-center justify-between mb-6">
                    <h2 className="text-2xl font-bold text-persivia-blue">
                        Edit {slide?.type} Slide
                    </h2>
                    <button
                        onClick={onClose}
                        className="p-2 hover:bg-persivia-light-gray/50 rounded-lg transition-colors"
                    >
                        <svg
                            className="w-6 h-6"
                            fill="none"
                            stroke="currentColor"
                            viewBox="0 0 24 24"
                        >
                            <path
                                strokeLinecap="round"
                                strokeLinejoin="round"
                                strokeWidth="2"
                                d="M6 18L18 6M6 6l12 12"
                            />
                        </svg>
                    </button>
                </div>

                {/* Edit Form */}
                <div className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium mb-1">
                            Image URL
                        </label>
                        <input
                            type="text"
                            value={editedSlide?.data.imageUrl || ""}
                            onChange={(e) =>
                                setEditedSlide((prev) =>
                                    prev
                                        ? {
                                            ...prev,
                                            data: {
                                                ...prev.data,
                                                imageUrl: e.target.value,
                                            },
                                        }
                                        : null
                                )
                            }
                            className="w-full px-3 py-2 border border-persivia-light-gray rounded-lg"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium mb-1">
                            Caption
                        </label>
                        <input
                            type="text"
                            value={editedSlide?.data.caption || ""}
                            onChange={(e) =>
                                setEditedSlide((prev) =>
                                    prev
                                        ? {
                                            ...prev,
                                            data: {
                                                ...prev.data,
                                                caption: e.target.value,
                                            },
                                        }
                                        : null
                                )
                            }
                            className="w-full px-3 py-2 border border-persivia-light-gray rounded-lg"
                        />
                    </div>

                    <div>
                        <label className="block text-sm font-medium mb-1">
                            Duration (seconds)
                        </label>
                        <input
                            type="number"
                            value={editedSlide?.duration || 5}
                            onChange={(e) =>
                                setEditedSlide((prev) =>
                                    prev
                                        ? {
                                            ...prev,
                                            duration: Number(e.target.value),
                                        }
                                        : null
                                )
                            }
                            min="1"
                            className="w-full px-3 py-2 border border-persivia-light-gray rounded-lg"
                        />
                    </div>
                </div>

                {/* Action Buttons */}
                <div className="flex justify-end gap-3 mt-6">
                    <button
                        onClick={onClose}
                        className="px-4 py-2 text-persivia-blue hover:bg-persivia-light-gray/50 rounded-lg transition-colors"
                    >
                        Cancel
                    </button>
                    <button
                        onClick={handleSave}
                        className="px-4 py-2 bg-persivia-blue text-white hover:bg-persivia-blue/90 rounded-lg transition-colors"
                    >
                        Save Changes
                    </button>
                </div>
            </motion.div>
        </div>
    );
};

const AdminPage: React.FC = () => {
    const { slides, addSlide, updateSlide } = useSlides();
    const [selectedSlide, setSelectedSlide] = useState<ImageSlide | null>(null);
    const [isEditModalOpen, setIsEditModalOpen] = useState(false);

    const handleCreateSlide = (type: typeof SLIDE_TYPES.IMAGE) => {
        const newSlide: ImageSlide = {
            id: `slide-${Date.now()}`,
            type,
            name: `New ${type} Slide`,
            duration: 5,
            active: true,
            dataSource: "manual",
            data: {
                imageUrl: "",
                caption: "",
            },
        };

        addSlide(newSlide);
        setSelectedSlide(newSlide);
        setIsEditModalOpen(true);
    };

    const handleEditSlide = (slide: ImageSlide) => {
        setSelectedSlide(slide);
        setIsEditModalOpen(true);
    };

    const handleSaveSlide = (updatedSlide: ImageSlide) => {
        updateSlide(updatedSlide);
    };

    return (
        <div className="min-h-screen bg-persivia-light-gray/50 p-6">
            <div className="max-w-7xl mx-auto">
                {/* Header */}
                <div className="mb-8">
                    <h1 className="text-3xl font-bold text-persivia-blue mb-2">
                        Slide Management
                    </h1>
                    <p className="text-persivia-gray">
                        Create and manage your display slides
                    </p>
                </div>

                {/* Available Slide Types */}
                <section className="mb-12">
                    <h2 className="text-xl font-semibold text-persivia-blue mb-4">
                        Available Slide Types
                    </h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {SLIDE_TYPE_CARDS.map((card) => (
                            <motion.div
                                key={card.type}
                                whileHover={{ scale: 1.02 }}
                                whileTap={{ scale: 0.98 }}
                                className="bg-white rounded-xl p-6 shadow-sm hover:shadow-md transition-shadow cursor-pointer"
                                onClick={() => handleCreateSlide(card.type)}
                            >
                                <div className="text-persivia-blue mb-4">{card.icon}</div>
                                <h3 className="text-lg font-semibold mb-2">{card.title}</h3>
                                <p className="text-persivia-gray text-sm">
                                    {card.description}
                                </p>
                            </motion.div>
                        ))}
                    </div>
                </section>

                {/* Existing Slides */}
                <section>
                    <h2 className="text-xl font-semibold text-persivia-blue mb-4">
                        Existing Slides
                    </h2>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {slides
                            .filter((slide): slide is ImageSlide => slide.type === SLIDE_TYPES.IMAGE)
                            .map((slide) => (
                                <motion.div
                                    key={slide.id}
                                    whileHover={{ scale: 1.02 }}
                                    whileTap={{ scale: 0.98 }}
                                    className="bg-white rounded-xl p-6 shadow-sm hover:shadow-md transition-shadow cursor-pointer"
                                    onClick={() => handleEditSlide(slide)}
                                >
                                    <div className="flex items-start justify-between mb-4">
                                        <div className="text-persivia-blue">
                                            {SLIDE_TYPE_CARDS.find(
                                                (card) => card.type === slide.type
                                            )?.icon}
                                        </div>
                                        <div
                                            className={`px-2 py-1 rounded text-xs font-medium ${slide.active
                                                ? "bg-green-100 text-green-700"
                                                : "bg-slate-100 text-slate-700"
                                                }`}
                                        >
                                            {slide.active ? "Active" : "Inactive"}
                                        </div>
                                    </div>
                                    <h3 className="text-lg font-semibold mb-2">
                                        {slide.name}
                                    </h3>
                                    <div className="text-persivia-gray text-sm space-y-1">
                                        <p>Type: {slide.type}</p>
                                        <p>Duration: {slide.duration}s</p>
                                        <p className="truncate">
                                            URL: {slide.data.imageUrl || "No image set"}
                                        </p>
                                    </div>
                                </motion.div>
                            ))}
                    </div>
                </section>
            </div>

            {/* Edit Modal */}
            <AnimatePresence>
                {isEditModalOpen && (
                    <EditModal
                        isOpen={isEditModalOpen}
                        onClose={() => setIsEditModalOpen(false)}
                        slide={selectedSlide}
                        onSave={handleSaveSlide}
                    />
                )}
            </AnimatePresence>
        </div>
    );
};

export default AdminPage;
